    parameter [10:0] SpriteY_Max = 312;

    always_comb begin
        if ((SpriteY < SpriteY_Max) && falling) begin
            // in the air but falling, switch to falling sprites
            if (lizard) begin
                q = lizard_falling_ROM[addr];
            end
            else begin
                q = alien_falling_ROM[addr];
            end
        end
        else if (SpriteY < SpriteY_Max) begin
            if (lizard) begin
                q = lizard_jumping_ROM[addr];
            end
            else begin
                q = alien_jumping_ROM[addr];
            end
        end
        else begin
            case (sprite_select)
                2'b00:   q = lizard ? lizard_standing_ROM[addr] : standing_ROM[addr];
                2'b01:   q = lizard ? lizard_left_foot_ROM[addr] : alien_left_foot_ROM[addr];
                2'b10:   q = lizard ? lizard_right_foot_ROM[addr] : alien_right_foot_ROM[addr];
                default: q = lizard ? lizard_standing_ROM[addr] : standing_ROM[addr];  // safe fallback
            endcase
        end
    end
